SimError make_err(SimError::Kind k, std::string detail) {
  return SimError{k, std::move(detail)};
}

sim_expected<void>
validate_thresholds(const Eigen::VectorXd& thresholds,
                    const std::string& caller,
                    Eigen::Index column) {
  if (thresholds.size() == 0) {
    return std::unexpected(make_err(
        SimError::Kind::InvalidInput,
        caller + ": ordinal thresholds must not be empty for column " +
            std::to_string(column)));
  }
  for (Eigen::Index k = 0; k < thresholds.size(); ++k) {
    if (!std::isfinite(thresholds(k))) {
      return std::unexpected(make_err(
          SimError::Kind::InvalidInput,
          caller + ": ordinal thresholds must be finite for column " +
              std::to_string(column)));
    }
    if (k > 0 && !(thresholds(k - 1) < thresholds(k))) {
      return std::unexpected(make_err(
          SimError::Kind::InvalidInput,
          caller + ": ordinal thresholds must be strictly increasing for column " +
              std::to_string(column)));
    }
  }
  return {};
}

int ordinal_category(double x, const Eigen::VectorXd& thresholds) noexcept {
  int category = 1;
  for (Eigen::Index k = 0; k < thresholds.size(); ++k) {
    if (x <= thresholds(k)) break;
    ++category;
  }
  return category;
}

std::vector<std::string> default_group_labels(std::size_t n_groups) {
  std::vector<std::string> labels;
  labels.reserve(n_groups);
  for (std::size_t g = 0; g < n_groups; ++g) {
    labels.push_back(std::to_string(g + 1));
  }
  return labels;
}

std::vector<std::vector<std::string>>
default_ordinal_level_labels(const MixedProjectionResult& result) {
  const auto p = static_cast<std::size_t>(result.X.cols());
  std::vector<std::vector<std::string>> labels(p);
  for (std::size_t v = 0; v < p; ++v) {
    const bool ordered = v < result.ordered.size() && result.ordered[v] == 1;
    if (!ordered) continue;
    const int k = (v < result.n_levels.size()) ? result.n_levels[v] : 0;
    for (int c = 1; c <= k; ++c) labels[v].push_back(std::to_string(c));
  }
  return labels;
}

